{
  "query": "mutation Login($input: LoginInput!) {
  login(input: $input) {
    token
    mustChangePassword
    user {
      id
      username
      displayName
      email
      role
    }
  }
}",
  "variables": {
    "input": {
      "email": "admin@platform.local",
      "password": "ChangeMe123!",
      "remember": true
    }
  }
}

{
  "query": "query Me {
  me {
    id
    username
    displayName
    email
    role
    mustChangePassword
